import React, { useState, useRef, useEffect } from 'react';
import { predictInteraction, searchDrugs } from '../services/api';
import toast from 'react-hot-toast';
import './DrugSearchForm.css';

function RiskBadge({ level }) {
  const map = {
    High: 'badge-high', Moderate: 'badge-moderate',
    Low: 'badge-low', Unknown: 'badge-unknown',
  };
  const icons = { High: '🔴', Moderate: '🟡', Low: '🟢', Unknown: '⚪' };
  return (
    <span className={`badge ${map[level] || 'badge-unknown'}`}>
      {icons[level] || '⚪'} {level}
    </span>
  );
}

function DrugAutocomplete({ label, value, onChange, placeholder }) {
  const [suggestions, setSuggestions] = useState([]);
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const handler = (e) => { if (!ref.current?.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const handleInput = async (e) => {
    const val = e.target.value;
    onChange(val);
    if (val.length >= 2) {
      try {
        const res = await searchDrugs(val);
        setSuggestions(res.data.drugs || []);
        setOpen(true);
      } catch { setSuggestions([]); }
    } else {
      setSuggestions([]); setOpen(false);
    }
  };

  return (
    <div className="autocomplete-wrap" ref={ref}>
      <div className="form-group">
        <label>{label}</label>
        <input
          className="form-input"
          value={value}
          onChange={handleInput}
          placeholder={placeholder}
          autoComplete="off"
          onFocus={() => suggestions.length > 0 && setOpen(true)}
        />
      </div>
      {open && suggestions.length > 0 && (
        <ul className="suggestions">
          {suggestions.map((s) => (
            <li key={s} onClick={() => { onChange(s); setOpen(false); setSuggestions([]); }}>
              💊 {s}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default function DrugSearchForm({ compact = false }) {
  const [drug1, setDrug1] = useState('');
  const [drug2, setDrug2] = useState('');
  const [age, setAge] = useState('');
  const [gender, setGender] = useState('');
  const [conditions, setConditions] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const resultRef = useRef(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!drug1.trim() || !drug2.trim()) {
      toast.error('Please enter both drug names'); return;
    }
    setLoading(true); setResult(null);
    try {
      const payload = {
        drug1: drug1.trim(),
        drug2: drug2.trim(),
        age: age ? parseInt(age) : null,
        gender: gender || null,
        health_conditions: conditions
          ? conditions.split(',').map((c) => c.trim()).filter(Boolean)
          : null,
      };
      const res = await predictInteraction(payload);
      setResult(res.data);
      setTimeout(() => resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 100);
    } catch {
      toast.error('Failed to check interaction. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const resultClass = {
    High: 'result-high', Moderate: 'result-moderate',
    Low: 'result-low', Unknown: 'result-unknown',
  }[result?.risk_level] || 'result-unknown';

  return (
    <div className="drug-search-form">
      <form onSubmit={handleSubmit}>
        <div className="drug-inputs-row">
          <DrugAutocomplete
            label="Drug 1"
            value={drug1}
            onChange={setDrug1}
            placeholder="e.g. Aspirin"
          />
          <div className="vs-divider">VS</div>
          <DrugAutocomplete
            label="Drug 2"
            value={drug2}
            onChange={setDrug2}
            placeholder="e.g. Warfarin"
          />
        </div>

        {!compact && (
          <div className="optional-row">
            <div className="form-group">
              <label>Age (optional)</label>
              <input
                className="form-input"
                type="number" min="1" max="120"
                value={age} onChange={(e) => setAge(e.target.value)}
                placeholder="e.g. 65"
              />
            </div>
            <div className="form-group">
              <label>Gender (optional)</label>
              <select className="form-input" value={gender} onChange={(e) => setGender(e.target.value)}>
                <option value="">Select</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </div>
            <div className="form-group" style={{ flex: 2 }}>
              <label>Health Conditions (optional, comma-separated)</label>
              <input
                className="form-input"
                value={conditions} onChange={(e) => setConditions(e.target.value)}
                placeholder="e.g. diabetes, kidney disease"
              />
            </div>
          </div>
        )}

        <button type="submit" className="btn btn-primary search-btn" disabled={loading}>
          {loading ? <><span className="spinner" style={{width:18,height:18}}></span> Checking...</> : '🔍 Check Interaction'}
        </button>
      </form>

      {result && (
        <div ref={resultRef} className={`result-card ${resultClass}`}>
          <div className="result-header">
            <div className="result-drugs">
              <span className="drug-pill">{result.drug1}</span>
              <span className="plus">+</span>
              <span className="drug-pill">{result.drug2}</span>
            </div>
            <RiskBadge level={result.risk_level} />
          </div>

          {result.found ? (
            <div className="result-body">
              {result.interaction_effect && (
                <div className="result-row">
                  <span className="result-label">Effect</span>
                  <span>{result.interaction_effect}</span>
                </div>
              )}
              {result.interaction_description && (
                <div className="result-row">
                  <span className="result-label">Description</span>
                  <span>{result.interaction_description}</span>
                </div>
              )}
              {result.interaction_type && (
                <div className="result-row">
                  <span className="result-label">Type</span>
                  <span className="type-tag">{result.interaction_type.replace('_', ' ')}</span>
                </div>
              )}
              {result.confidence_score && (
                <div className="result-row">
                  <span className="result-label">Confidence</span>
                  <div className="confidence-bar-wrap">
                    <div className="confidence-bar">
                      <div
                        className="confidence-fill"
                        style={{ width: `${result.confidence_score * 100}%` }}
                      />
                    </div>
                    <span>{Math.round(result.confidence_score * 100)}%</span>
                  </div>
                </div>
              )}
              {result.patient_risk_note && (
                <div className="risk-note">
                  ℹ️ {result.patient_risk_note}
                </div>
              )}
            </div>
          ) : (
            <p className="no-interaction">
              ✅ No known interaction found between these two drugs in our dataset.
            </p>
          )}
        </div>
      )}
    </div>
  );
}
